var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>다음 소식입니다.</color>","JPN":"<color=#ffd34c>次のニュースです。</color>","ENG":"<color=#ffd34c>Our next story.</color>","TWN":"<color=#ffd34c>下一則新聞。</color>"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_05"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>오늘 오후, ARC-KN2 교외에서 일어난 원인 불명의 침식재난으로 다수의 사상자가 발생했습니다.</color>","JPN":"<color=#ffd34c>本日午後、ARC-KN2郊外で起きた原因不明の侵食災害によって、複数の死傷者が発生しました。</color>","ENG":"<color=#ffd34c>This afternoon, multiple casualties have been reported from the unexplained Corruption Disaster that occurred on the outskirts of ARC-KN2.</color>","TWN":"<color=#ffd34c>今天下午在ARC-KN2郊區，發生不明原因的侵蝕災難，導致多人傷亡。</color>"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그 중에는 육상 대회에 참가하기 위해 이동 중이던 학생들도 포함되어 있어 큰 충격을 안겼습니다.</color>","JPN":"<color=#ffd34c>中には陸上大会に参加するために移動していた学生たちも含まれており、大きな衝撃を与えました。</color>","ENG":"<color=#ffd34c>Among the casualties are students who were on their way to a track event, causing much shock to the public.</color>","TWN":"<color=#ffd34c>當中也有正要前往參與田徑賽的學生，因此造成相當大的衝擊。</color>"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재 KN2 도시 관리국은 사상자 신원의 파악과 재난의 원인을 밝히는 데에 주력하고 있습니다.</color>","JPN":"<color=#ffd34c>現在、KN2都市管理局は死傷者の身元の把握と災害の原因究明に努めています。</color>","ENG":"<color=#ffd34c>Currently, the KN2 city administration is focusing its efforts towards identifying the victims and uncovering the cause of the disaster.</color>","TWN":"<color=#ffd34c>至於傷亡人士的身分和災難發生的原因，KN2城市管理局目前正在積極調查中。</color>"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이어서 스포츠 소식 전해 드리겠습니다.</color>","JPN":"<color=#ffd34c>次のニュースをお伝えします。</color>","ENG":"<color=#ffd34c>Next, we bring you the latest in sports.</color>","TWN":"<color=#ffd34c>接著是體壇消息。</color>"},"stage":{"bg":"CITY_TWILIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"거의 다 왔어.","JPN":"そろそろ着く。","ENG":"We are almost there.","TWN":"就快到了。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"가까워질수록 왠지 속이 메스꺼운데……. 너도 그래?","JPN":"近づけば近づくほどなぜか吐き気が強くなるんだけど……\\n君もそう？","ENG":"The closer we get, the more nauseous I feel... Do you feel like that too?","TWN":"好像越接近目的地，就有種反胃的感覺……你也會嗎？"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그건 잘 모르겠지만, 머릿속이 지직거리는 것 같긴 해.","JPN":"その感覚はわからないけど、頭の中にジ、ジジッってノイズがかかる感じがする。","ENG":"I do not know how that feels, but I think my head is tingling.","TWN":"反胃是還好，我好像是腦袋裡會嗡嗡作響。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그건 또 무슨 기분이람. 그냥 기계에 문제 생긴 거 아냐?","JPN":"それはまたどういう気持ち？　ただ機械的な問題じゃない？","ENG":"What kind of feeling is that? Maybe that’s just a technical issue?","TWN":"這是什麼心情？會不會是機械故障？"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"더미 데이터 삭제 완료. 이제 문제없어.","JPN":"ダミーデータの削除完了。もう問題ない。","ENG":"Dummy data deletion completed. No issues now.","TWN":"虛擬資料刪除完畢，沒問題了。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그렇다면 다행이네.","JPN":"それなら安心。","ENG":"If you say so, that’s a relief.","TWN":"那就好。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"수아 넌 내 뒤에 잘 붙어서 따라와. 위험한 녀석이니까.","JPN":"コトリ、君は私の後ろにピッタリくっついて来て。\\nあいつは危ないやつだから。","ENG":"Skia, follow closely behind me. This one’s dangerous.","TWN":"蘇亞，你在我後面跟好，那傢伙很危險的！"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"응.","JPN":"うん。","ENG":"Okay.","TWN":"嗯。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……찾았다.","JPN":"……見つけた。","ENG":"...There you are.","TWN":"……找到了！"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_SWORD","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"저 끔찍한 눈동자…….","JPN":"あのぞっとする瞳……","ENG":"Those hideous eyes...","TWN":"那嚇人的眼珠……"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_SWORD","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"틀림없어. 꼭 잡아먹을 것처럼 붉게 빛나던…….","JPN":"間違いない。まるで獲物を狙っているかのように赤く光っていた……","ENG":"There’s no doubt about it. It’s those glowing red eyes, as if they were going to eat you...","TWN":"絕對沒錯！那個血盆大……"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_SWORD","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"도로시, 안아줄까?","JPN":"ドロシー、ハグしてあげようか？","ENG":"Dorothy, do you want a hug?","TWN":"桃樂絲，你要抱抱嗎？"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐?","JPN":"はあ？","ENG":"What?","TWN":"抱什麼抱？"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"기분이 안 좋아 보여서. 이럴 때 안아주면 기분 풀렸었잖아.","JPN":"顔色が悪いよ。こういう時、ハグしてあげたら落ち着いてたでしょ。","ENG":"You look upset. When I gave you a hug in these situations, you felt better.","TWN":"我看你心情不太好的樣子，這種時候抱抱不是可以緩和情緒嗎？"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……기억나?","JPN":"……覚えてたの？","ENG":"...You remember?","TWN":"……你記得？"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"당연하지. 다 제대로 저장…… 제대로 기억하고 있으니까.","JPN":"もちろん。すべてしっかり保存……ちゃんと覚えているから。","ENG":"Of course. It is all properly stored... I remember properly.","TWN":"當然，我都有儲存……都有記下來。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……안아주는 건 됐어. 그보다 준비는 다 됐지?","JPN":"……ハグはいいよ。それより、準備はできたよね？","ENG":"...I don’t need a hug. More importantly, are you prepared?","TWN":"……我現在不用抱啦，重點是你準備好沒？"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"잠시만.","JPN":"待って。","ENG":"Wait a moment.","TWN":"等我一下。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"어택 모드로 변경 완료.","JPN":"アタックモードに切り替え完了。","ENG":"Successfully changed to attack mode.","TWN":"攻擊模式轉換完畢。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L40_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이제 준비 다 했어.","JPN":"もう準備できた。","ENG":"Now I am ready.","TWN":"準備好了。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……너 솔직히 말해 봐.","JPN":"……正直に言ってほしいんだけど。","ENG":"...Be honest.","TWN":"……你老實說，"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"어택 모드라는 거. 디스플레이에 이모지만 바꾸는 거지?","JPN":"アタックモードって、ディスプレイの絵文字を変更してるだけだよね？","ENG":"The so-called attack mode, you only changed the emoji on the display, right?","TWN":"所謂的攻擊模式，其實只是在顯示器上換個貼圖吧？"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"맞아. 원래부터 탑재하고 있던 나의 재치지.","JPN":"イエス。元々搭載されていたワタシのセンスである。","ENG":"That is correct. It is my wit that was equipped from the beginning.","TWN":"沒錯，這是原本就有搭載的小聰明。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그리고, 마음을 굳게 먹는 것도 필요한 준비 과정이니까.","JPN":"あと、腹をくくるのも必要な準備過程だから。","ENG":"Also, steeling yourself is part of the preparation process.","TWN":"而且做好心理準備，也是不可或缺的準備過程。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐, 틀린 말은 아니네.","JPN":"まあ、間違ってはないね。","ENG":"Well, you're not wrong.","TWN":"嗯，話是沒錯。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……너는 정말 아무렇지도 않구나. 왠지 나만 열내는 것 같아.","JPN":"……君は本当に平気なんだね。\\nなんか私だけ熱くなってる気がする。","ENG":"...You really don’t feel anything. It seems like the only one getting mad is me.","TWN":"……怎麼好像只有我很激動，你感覺很平淡。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"미안. 내가 또 상황에 안 맞게 행동한 거지?","JPN":"ごめん。ワタシがまた空気読めない行動をしたんだよね？","ENG":"Sorry. I did not act appropriately to the situation again, right?","TWN":"抱歉，我的行為反應又和現況不符對吧？"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"저걸 봐도…… 별다른 감정이 안 떠올라.","JPN":"あれを見ても……これといった感情が浮かばない。","ENG":"Even when I look at it... I do not feel anything.","TWN":"我看到它後……還是沒什麼情緒反應。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"괜찮아. 그건 네 탓이 아니야.","JPN":"大丈夫。それは君のせいじゃない。","ENG":"It’s okay. That isn’t your fault.","TWN":"沒關係，這不是你的問題。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"무슨 소리야?","JPN":"何の音だ？","ENG":"What’s that sound?","TWN":"什麼聲音？"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"현재 용병으로 보이는 다수의 인물이 목표물에 접근 중.","JPN":"現在、傭兵とみられる複数の人物がターゲットに接近中。","ENG":"Multiple people are approaching the target. They look like mercenaries.","TWN":"現在多位疑似傭兵的人物向目標靠近中。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"아무래도 우리처럼 <color=#ffd34c>기생체</color>를 노리는 것 같아.","JPN":"どうやらワタシたちと同じく<color=#ffd34c>寄生体</color>を狙っているみたい。","ENG":"They seem to be after <color=#ffd34c>the parasite</color> just like us.","TWN":"應該和我們一樣，是針對<color=#ffd34c>寄生物</color>而來的。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그건 안 될 소리지.","JPN":"それはいけないね。","ENG":"Not on my watch.","TWN":"那可不行！"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MERCENARY_NPC_OZ_A","text":{"KOREA":"전방에 목표물 발견.","JPN":"前方にターゲット発見。","ENG":"Target spotted ahead.","TWN":"在前方發現目標！"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_OZ_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"MERCENARY_NPC_OZ_A","text":{"KOREA":"<color=#ffd34c>교수</color>의 의뢰다. 중요한 샘플이라더군.","JPN":"<color=#ffd34c>教授</color>の依頼だ。重要なサンプルだそうだ。","ENG":"This is a job from <color=#ffd34c>the professor</color>. Apparently it’s an important sample.","TWN":"這是<color=#ffd34c>教授</color>的委託，說是很重要的樣本。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_OZ_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L9_1","type":"dialog","speaker":"MERCENARY_NPC_OZ_A","text":{"KOREA":"소지자의 생명은 상관없다. 목표물 확보에만 집중하도록.","JPN":"所持者の生死は問わない。ターゲットの確保だけに集中しろ。","ENG":"The host’s life is irrelevant. Focus only on securing the target.","TWN":"持有者的性命無所謂，重點是要拿到目標物！"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_OZ_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"누구 마음대로 데려가?","JPN":"誰が勝手に連れてっていいって言った？","ENG":"Who gave you permission to take that?","TWN":"誰准你把它帶走的？"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MERCENARY_NPC_OZ_A","text":{"KOREA":"뭐야?","JPN":"何だ？","ENG":"What?","TWN":"你誰？"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"저건 우리 거니까 좋은 말 할 때 저리 꺼져. 엉덩이 걷어차여서 쫓겨나기 싫으면.","JPN":"あれは私たちのモノだから、今のうちに失せろ。\\nケツを蹴られて追い出されたくなかったらな。","ENG":"That’s ours, so if you don’t want to get your asses kicked, get lost while I’m still in a good mood.","TWN":"那是我們的，本小姐現在好聲好氣跟你講，你不要敬酒不吃吃罰酒，快滾！"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"MERCENARY_NPC_OZ_A","text":{"KOREA":"말이 험한 녀석이군. 업계 상도덕도 모르는 걸 보니 용병은 아닌 것 같고.","JPN":"口の悪いやつだな。\\n業界の常識も知らないのを見るに、傭兵ではなさそうだが。","ENG":"You have quite a mouth on you. And seeing that you lack professional etiquette, you’re probably not a mercenary.","TWN":"說話真是沒大沒小，而且一點職業道德也沒有，我看你應該不是傭兵。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"MERCENARY_NPC_OZ_A","text":{"KOREA":"어린애는 얌전히 돌아가서 발이나 닦고 자라. 카운턴지 뭔지 몰라도 함부로 끼어들 일이 아냐.","JPN":"ガキは大人しく帰ってろ。カウンターかどうかは知らないが、\\n足でもケガして泣いても知らんぞ。","ENG":"Run off as fast as your legs can carry you, kid. Regardless of whether you’re a Counter or something else, this is nothing to get tangled in.","TWN":"小鬼勸你趕快回家，把腳洗一洗上床睡覺吧！管你是制裁者還是什麼，這事不是你能插手的！"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"눈 삐었어? 닦을 발 없거든?","JPN":"その目は飾り？　ケガするもくそも、痛む足が無いんだけど。","ENG":"Are you blind? I don't have legs.","TWN":"你瞎啦？我沒有腳是要洗什麼？"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"헛소리 말고 그쪽이나 얌전히 돌아가. 더 알짱거리면 눈 깜짝하기도 전에 옆 동네로 날려 버릴 거니까.","JPN":"無駄話に付き合う暇はないから、そっちがさっさと帰れ。\\nこれ以上ウロチョロするなら、隣町までぶっ飛ばしてやるから。","ENG":"Enough with the nonsense and get lost. If you keep wasting my time, I’ll kick you into next week before you can blink.","TWN":"廢話少說，該離開的人是你！你再不走，我就把你一腳踢到外太空喔！"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MERCENARY_NPC_OZ_A","text":{"KOREA":"허풍이 심하군.","JPN":"ずいぶんとデカい口を叩くじゃねえか。","ENG":"You’re bluffing.","TWN":"還真會吹牛。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MERCENARY_NPC_OZ_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MERCENARY_NPC_OZ_A","text":{"KOREA":"의뢰를 완수하려면 저 녀석부터 처리해야겠어.","JPN":"依頼を完遂するにはあいつから処理しないとだな。","ENG":"We should get rid of her first to get this job done.","TWN":"看來必須先把那小鬼處理掉，才有辦法完成委託。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERCENARY_NPC_OZ_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……하여간 말 잘 듣는 어른을 못 봤어.","JPN":"……まったく。言うことを素直に聞いてくれる大人ってホントいないな。","ENG":"...Jeez, I’ve never met an adult that listens to me.","TWN":"……長輩的耳朵就是這麼硬！"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"수아. 잠시만 기다려. 금방 처리하고 올게.","JPN":"コトリ。ちょっと待ってて。すぐ済ませてくる。","ENG":"Skia, wait here. I’ll take care of this quickly.","TWN":"蘇亞，你等我一下，我處理完很快就回來。"},"stage":{"bg":"MYEONGDONG_DARK","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};